import React, { Component } from 'react';
import Modal from 'react-modal'; // react-bootstrap doesn't support modals on bootstrap 4 yet ...
import { Form, Row, Col, Button } from 'react-bootstrap';
import { connect } from 'react-redux';
import { userDetailToggle } from '../../actions/index';

const customStyles = {
  content: {
    top: '50%',
    left: '50%',
    right: 'auto',
    bottom: 'auto',
    marginRight: '-50%',
    transform: 'translate(-50%, -50%)'
  }
};

// Make sure to bind modal to your appElement (http://reactcommunity.org/react-modal/accessibility/)
Modal.setAppElement('#root');

class UserDetail extends Component {
  // Arrow fx for `this` binding
  closeModal = () => {
    this.props.userDetailToggle('');
  };

  render() {
    return (
      <div>
        <Modal
          isOpen={this.props.detailUserID !== ''}
          onAfterOpen={this.afterOpenModal}
          onRequestClose={this.closeModal}
          style={customStyles}
          contentLabel="Example Modal"
        >
          {this.props.currentUser ? (
            <>
              <h2>{this.props.currentUser.name.first} 's details :</h2>
              <hr />
              <Form>
                {this.props.currentUser.location.street !== '' ? (
                  <Form.Group as={Row} controlId="userStreet">
                    <Form.Label column sm={3}>
                      Street
                    </Form.Label>
                    <Col sm={9}>
                      <Form.Text disabled />
                      <Form.Control
                        type="text"
                        placeholder="Email"
                        disabled
                        value={this.props.currentUser.location.street}
                      />
                    </Col>
                  </Form.Group>
                ) : (
                  <></>
                )}

                {this.props.currentUser.location.postcode !== '' ? (
                  <Form.Group as={Row} controlId="userPostCode">
                    <Form.Label column sm={3}>
                      Postcode
                    </Form.Label>
                    <Col sm={9}>
                      <Form.Text disabled />
                      <Form.Control
                        type="text"
                        placeholder="Email"
                        disabled
                        value={this.props.currentUser.location.postcode}
                      />
                    </Col>
                  </Form.Group>
                ) : (
                  <></>
                )}

                {this.props.currentUser.location.city !== '' ? (
                  <Form.Group as={Row} controlId="userCity">
                    <Form.Label column sm={3}>
                      City
                    </Form.Label>
                    <Col sm={9}>
                      <Form.Text disabled />
                      <Form.Control
                        type="text"
                        placeholder="Email"
                        disabled
                        value={this.props.currentUser.location.city}
                      />
                    </Col>
                  </Form.Group>
                ) : (
                  <></>
                )}

                {this.props.currentUser.location.state !== '' ? (
                  <Form.Group as={Row} controlId="userState">
                    <Form.Label column sm={3}>
                      State
                    </Form.Label>
                    <Col sm={9}>
                      <Form.Text disabled />
                      <Form.Control
                        type="text"
                        placeholder="Email"
                        disabled
                        value={this.props.currentUser.location.state}
                      />
                    </Col>
                  </Form.Group>
                ) : (
                  <></>
                )}

                {this.props.currentUser.phone !== '' ? (
                  <Form.Group as={Row} controlId="userPhone">
                    <Form.Label column sm={3}>
                      Phone
                    </Form.Label>
                    <Col sm={9}>
                      <Form.Text disabled />
                      <Form.Control
                        type="text"
                        placeholder="Email"
                        disabled
                        value={this.props.currentUser.phone}
                      />
                    </Col>
                  </Form.Group>
                ) : (
                  <></>
                )}

                {this.props.currentUser.cell !== '' ? (
                  <Form.Group as={Row} controlId="userCell">
                    <Form.Label column sm={3}>
                      Cell
                    </Form.Label>
                    <Col sm={9}>
                      <Form.Text disabled />
                      <Form.Control
                        type="text"
                        placeholder="Email"
                        disabled
                        value={this.props.currentUser.cell}
                      />
                    </Col>
                  </Form.Group>
                ) : (
                  <></>
                )}
                <Col sm={{ span: 4, offset: 4 }}>
                  <Button variant="primary" onClick={() => this.closeModal()}>
                    Close
                  </Button>
                </Col>
              </Form>
            </>
          ) : (
            <></>
          )}
        </Modal>
      </div>
    );
  }
}

function mapStateToProps(state) {
  return {
    detailUserID: state.detailUserID,
    currentUser: state.currentUser
  };
}

export default connect(
  mapStateToProps,
  { userDetailToggle }
)(UserDetail);
