import React, { Component } from 'react';
import PropTypes from 'prop-types';
import { Card, Button, Image, Container, Row, Col } from 'react-bootstrap';
import { connect } from 'react-redux';
import { userDetailToggle } from '../../actions/index';

class User extends Component {
  userImage(picture) {
    return picture ? (
      <Image src={picture.thumbnail} roundedCircle />
    ) : (
      <span className="glyphicon glyphicon-user" aria-hidden="true" />
    );
  }

  userInfo(name) {
    return name ? [name.first, name.last].join(' ') : 'Nothing to show';
  }

  userDetails(login, email) {
    return [login ? login.username : '', email ? email : ''].join(' ');
  }

  render() {
    return (
      <Card style={{ width: '18rem' }}>
        <Container>
          <Row>
            <Col>{this.userImage(this.props.user.picture)}</Col>
          </Row>
        </Container>

        <Card.Body>
          <Card.Title> {this.userInfo(this.props.user.name)}</Card.Title>
          <Card.Text>{this.userDetails(this.props.user.login, this.props.user.email)}</Card.Text>
          <Button
            variant="primary"
            disabled={!this.props.user.name}
            onClick={() => this.props.userDetailToggle(this.props.user.login.uuid)}
          >
            Details
          </Button>
        </Card.Body>
      </Card>
    );
  }
}

User.propTypes = {
  index: PropTypes.number.isRequired
};

export default connect(
  null,
  { userDetailToggle }
)(User);
