import React, { Component } from 'react';
import User from './User';
import { connect } from 'react-redux';
import { getData, appendData, mergeData } from '../../actions/index';
import InfiniteScroll from 'react-infinite-scroller';

class UserList extends Component {
  componentDidMount() {
    this.props.getData(); // Load the first batch of users...
  }

  appendData() {
    if (this.props.nextUsersBatch.length > 0) {
      // There is a user arary prepared in advance => merge it to the current users array
      this.props.mergeData();
    }
    // Prepare the next user batch of data
    this.props.appendData();
  }

  render() {
    return (
      <main role="main" className="container">
        <div className="box">
          <div className="container">
            <InfiniteScroll
              pageStart={0}
              loadMore={() => this.appendData()} // Arrow fx for `this` binding
              hasMore={!(this.props.endReached || this.props.isFetching)}
              loader={
                <div className="loader" key={0}>
                  Loading ...
                  <div className="spinner-border" role="status" />
                </div>
              }
            >
              <div className="row">
                {this.props.users.map((user, index) => (
                  <User user={user} key={index} index={index} />
                ))}
              </div>
            </InfiniteScroll>

            <div>{this.props.endReached ? <h3>End of users catalog :-)</h3> : <></>}</div>
          </div>
        </div>
      </main>
    );
  }
}

function mapStateToProps(state) {
  return {
    users: state.users,
    nextUsersBatch: state.nextUsersBatch,
    isFetching: state.isFetching,
    endReached: state.endReached
  };
}

export default connect(
  mapStateToProps,
  { getData, appendData, mergeData }
)(UserList);
